80	// parseClaudeStream reads newline-delimited claude stream-json events from r,
81	// writes translated progress entries to progressLog (one JSONL line per tool
82	// call and a session.start event on init), and returns an aggregated
83	// claudeStreamResult covering token usage, final text, and counts.
84	//
85	// The progress entries use the same event type names the ddx-agent harness
86	// emits (session.start, tool.call, llm.response) so the existing
87	// TailSessionLogs / FormatSessionLogLines pipeline can render them as
88	// real-time progress without any changes.
89	//
90	// beadID and startTime are optional: when provided, each progress entry
91	// receives a data.bead_id and data.elapsed_ms field for cross-referencing.
92	//
93	// progressLog may be nil; if nil, progress entries are discarded but the
94	// aggregate result is still returned.
95	func parseClaudeStream(r io.Reader, progressLog io.Writer, sessionID, beadID string, startTime time.Time) (*claudeStreamResult, error) {
96		if startTime.IsZero() {
97			startTime = time.Now()
98		}
99		res := &claudeStreamResult{SessionID: sessionID}
100		scanner := bufio.NewScanner(r)
101		scanner.Buffer(make([]byte, 0, 256*1024), 16*1024*1024) // 16MB max line — claude can dump big tool results
102	
103		seq := 0
104		emit := func(evType, dataJSON string) {
105			if progressLog == nil {
106				return
107			}
108			entry := map[string]any{
109				"session_id": sessionID,
110				"seq":        seq,
111				"type":       evType,
112				"ts":         time.Now().UTC().Format(time.RFC3339Nano),
113				"data":       json.RawMessage(dataJSON),
114			}
115			seq++
116			line, err := json.Marshal(entry)
117			if err != nil {
118				return
119			}
120			_, _ = progressLog.Write(line)
121			_, _ = progressLog.Write([]byte("\n"))
122		}
123	
124		wroteStart := false
125		// lastRequestSentAt tracks when the most recent LLM request was sent.
126		// For the first turn it equals startTime (the session began with a
127		// request). After every "user" event (tool_result returned to the model)
128		// we reset it: the next assistant event represents a new round-trip.
129		// Per-call latency is then `now - lastRequestSentAt`, distinct from
130		// cumulative elapsed_ms.
131		lastRequestSentAt := startTime
132		for scanner.Scan() {
133			line := strings.TrimSpace(scanner.Text())
134			if line == "" {
135				continue
136			}
137			var ev claudeStreamEvent
138			if err := json.Unmarshal([]byte(line), &ev); err != nil {
139				// Not a JSON event — skip silently to be lenient.
140				continue
141			}
142	
143			now := time.Now()
144			elapsedMS := now.Sub(startTime).Milliseconds()
145			switch ev.Type {
146			case "system":
147				if ev.Subtype == "init" && !wroteStart {
148					wroteStart = true
149					if ev.Model != "" {
150						res.Model = ev.Model
151					}
152					if ev.SessionID != "" {
153						res.SessionID = ev.SessionID
154					}
155					data, _ := json.Marshal(map[string]any{
156						"model":      res.Model,
157						"session_id": res.SessionID,
158						"bead_id":    beadID,
159						"elapsed_ms": elapsedMS,
160						"harness":    "claude",
161					})
162					emit("session.start", string(data))
163				}
164	
165			case "assistant":
166				var msg claudeAssistantMessage
167				if len(ev.Message) > 0 {
168					_ = json.Unmarshal(ev.Message, &msg)
169				}
170				if msg.Model != "" && res.Model == "" {
171					res.Model = msg.Model
172				}
173				// Running usage totals so TailSessionLogs has the latest view.
174				if msg.Usage.InputTokens > 0 {
175					res.InputTokens = msg.Usage.InputTokens
176				}
177				if msg.Usage.OutputTokens > 0 {
178					res.OutputTokens = msg.Usage.OutputTokens
179				}
180	
181				// Count each assistant message as one turn for operator visibility.
182				res.TurnCount++
183	
184				// Collect tool-use names emitted in this turn, so we can translate
185				// the assistant event into an llm.response-like progress entry.
186				var toolNames []map[string]string
187				var textOut strings.Builder
188				for _, block := range msg.Content {
189					switch block.Type {
190					case "text":
191						if block.Text != "" {
192							if textOut.Len() > 0 {
193								textOut.WriteString("\n")
194							}
195							textOut.WriteString(block.Text)
196						}
197					case "tool_use":
198						name := block.Name
199						if name == "" {
200							name = "tool"
201						}
202						toolNames = append(toolNames, map[string]string{"name": name})
203					}
204				}
205	
206				latencyMS := now.Sub(lastRequestSentAt).Milliseconds()
207				if latencyMS < 0 {
208					latencyMS = 0
209				}
210				data, _ := json.Marshal(map[string]any{
211					"model":         res.Model,
212					"latency_ms":    latencyMS,
213					"tool_calls":    toolNames,
214					"turn":          res.TurnCount,
215					"bead_id":       beadID,
216					"elapsed_ms":    elapsedMS,
217					"input_tokens":  res.InputTokens,
218					"output_tokens": res.OutputTokens,
219					"attempt": map[string]any{
220						"cost": map[string]any{
221							"raw": map[string]any{
222								"total_tokens": res.InputTokens + res.OutputTokens,
223							},
224						},
225					},
226				})
227				emit("llm.response", string(data))
228	
229				// Emit a tool.call entry for each tool_use block so progress
230				// output shows per-tool lines (matches ddx-agent format).
231				for _, block := range msg.Content {
232					if block.Type != "tool_use" {
233						continue
234					}
235					res.ToolCalls++
236					input := map[string]any{}
237					if len(block.Input) > 0 {
238						_ = json.Unmarshal(block.Input, &input)
239					}
240					toolData, _ := json.Marshal(map[string]any{
241						"tool":       block.Name,
242						"input":      input,
243						"bead_id":    beadID,
244						"elapsed_ms": elapsedMS,
245						"turn":       res.TurnCount,
246					})
247					emit("tool.call", string(toolData))
248				}
249	
250				// Save the most recent text content so, if the final result
251				// event is missing or truncated, we can still return the
252				// agent's last spoken text.
253				if t := textOut.String(); t != "" {
254					res.FinalText = t
255				}
256	
257			case "user":
258				// user events carry tool_result content. Not useful for progress,
259				// already captured by the tool.call timing above. They do mark
260				// the moment the next LLM request is sent, so we reset the
261				// per-call latency baseline here.
262				lastRequestSentAt = now
263	
264			case "result":
265				// Final event. Extract authoritative usage/cost/result text.
266				if ev.Result != "" {
267					res.FinalText = ev.Result
268				}
269				if ev.Usage.InputTokens > 0 {
270					res.InputTokens = ev.Usage.InputTokens
271				}
272				if ev.Usage.OutputTokens > 0 {
273					res.OutputTokens = ev.Usage.OutputTokens
274				}
275				if ev.TotalCostUSD > 0 {
276					res.CostUSD = ev.TotalCostUSD
277				}
278				if ev.SessionID != "" {
279					res.SessionID = ev.SessionID
280				}
281				if ev.IsError {
282					res.IsError = true
283				}
284			}
285		}
286		if err := scanner.Err(); err != nil && !errors.Is(err, io.EOF) {
287			return res, err
288		}
289		return res, nil
290	}
291	
292	// resolveClaudeProgressLogDir picks the directory for the per-run claude
293	// progress JSONL trace. The per-run override (opts.SessionLogDir) takes
294	// precedence over the runner-wide Config.SessionLogDir so managed
295	// execute-bead invocations can redirect the trace into the DDx-owned
296	// execution bundle's embedded/ dir instead of the runner's default
297	// .ddx/agent-logs. Matches the agent_runner.go precedence pattern so the
298	// two harnesses behave identically under execute-bead.
299	func resolveClaudeProgressLogDir(opts RunArgs, cfg Config) string {
300		if opts.SessionLogDir != "" {
301			return opts.SessionLogDir
302		}
303		return cfg.SessionLogDir
304	}
305	
306	// runClaudeStreaming is the streaming execution path for the claude harness.
307	// It launches the claude binary directly (bypassing the standard Executor
308	// abstraction so it can pipe stdout line-by-line), parses stream-json events
309	// as they arrive, and writes per-tool progress entries to a ddx-agent-style
310	// JSONL file in opts.SessionLogDir (when set) or r.Config.SessionLogDir so
311	// `ddx server workers log` sees real-time activity.
312	//
313	// On success it returns a *Result shaped exactly like the non-streaming
314	// path, so callers downstream (processResult, session logging) are unchanged.
315	//
316	// If the claude CLI rejects the stream-json flags (older build, unsupported
317	// option), the caller falls back to the non-streaming path via
318	// runClaudeWithFallbackFn.
319	func runClaudeStreamingFn(r *Runner, ctx context.Context, harness harnessConfig, harnessName, model string, resolvedOpts RunArgs, prompt, execDir string, timeout time.Duration) (*Result, error) {
320		args := BuildArgs(harness, buildArgsInputFromRunArgs(resolvedOpts), model)
321	
322		start := time.Now()
323		runCtx, cancel := context.WithCancel(ctx)
324		defer cancel()
325	
326		cmd := osexec.CommandContext(runCtx, harness.Binary, args...)
327		if execDir != "" {
328			cmd.Dir = execDir
329		}
330		if harness.PromptMode == "stdin" {
331			cmd.Stdin = strings.NewReader(prompt)
332		}
333	
334		stdoutPipe, err := cmd.StdoutPipe()
335		if err != nil {
336			return nil, err
337		}
338		stderrPipe, err := cmd.StderrPipe()
339		if err != nil {
340			return nil, err
341		}
342	
343		if err := cmd.Start(); err != nil {
344			return nil, err
345		}
346	
347		// Open the progress log file. Using agent-<sessionID>.jsonl so
348		// TailSessionLogs (which only reads files matching "agent-*.jsonl")
349		// picks the stream up automatically.
350		sessionID := fmt.Sprintf("claude-%d", time.Now().UnixNano())
351		beadID := ""
352		if resolvedOpts.Correlation != nil {
353			beadID = resolvedOpts.Correlation["bead_id"]
354		}
355		var progressLog *os.File
356		progressLogDir := resolveClaudeProgressLogDir(resolvedOpts, r.Config)
357		if progressLogDir != "" {
358			if err := os.MkdirAll(progressLogDir, 0o755); err == nil {
359				logPath := filepath.Join(progressLogDir, "agent-"+sessionID+".jsonl")
360				if f, err := os.OpenFile(logPath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644); err == nil {
361					progressLog = f
362					defer progressLog.Close()
363				}
364			}
365		}
366	
367		// Stream stdout: parse events as they arrive and mirror raw bytes into
368		// a buffer so we can return the full output for session logging.
369		var rawOut strings.Builder
370		stdoutReader, stdoutWriter := io.Pipe()
371		var parseResult *claudeStreamResult
372		var parseErr error
373		var parseWG sync.WaitGroup
374		parseWG.Add(1)
375		go func() {
376			defer parseWG.Done()
377			parseResult, parseErr = parseClaudeStream(stdoutReader, progressLog, sessionID, beadID, start)
378		}()
379	
380		// Tee stdout into rawOut (for the final Result.Output) and the parser.
381		stdoutDone := make(chan struct{})
382		go func() {
383			defer close(stdoutDone)
384			// Pipe bytes through a tee so both the raw buffer and the parser see them.
385			tee := io.TeeReader(stdoutPipe, &stringWriter{&rawOut})
386			_, _ = io.Copy(stdoutWriter, tee)
387			_ = stdoutWriter.Close()
388		}()
389	
390		var stderrBuf strings.Builder
391		stderrDone := make(chan struct{})
392		go func() {
393			defer close(stderrDone)
394			_, _ = io.Copy(&stringWriter{&stderrBuf}, stderrPipe)
395		}()
396	
397		// Idle-timeout watchdog: if no stdout progress for `timeout` duration,
398		// cancel the context. The tee+parse goroutines handle activity naturally
399		// via the pipe; for simplicity we use an overall deadline here. The
400		// existing stream-json output is frequent enough that a long per-bead
401		// deadline is the right behavior for operators.
402		var timedOut bool
403		if timeout > 0 {
404			stop := make(chan struct{})
405			go func() {
406				select {
407				case <-stop:
408				case <-time.After(timeout):
409					timedOut = true
410					cancel()
411				}
412			}()
413			defer close(stop)
414		}
415	
416		<-stdoutDone
417		<-stderrDone
418		parseWG.Wait()
419		runErr := cmd.Wait()
420		elapsed := time.Since(start)
421	
422		exitCode := 0
423		if runErr != nil {
424			if exitErr, ok := runErr.(*osexec.ExitError); ok {
