477	// claudeStreamArgsUnsupported reports whether the claude CLI rejected the
478	// stream-json flags. Used by the fallback path to retry with legacy args.
479	func claudeStreamArgsUnsupported(stderr string) bool {
480		lower := strings.ToLower(stderr)
481		return strings.Contains(lower, "unknown option") ||
482			strings.Contains(lower, "unrecognized option") ||
483			strings.Contains(lower, "invalid value for --output-format") ||
484			strings.Contains(lower, "unknown argument") ||
485			strings.Contains(lower, "unknown flag")
486	}
487	
488	// runClaudeWithFallback attempts the streaming path first and, if the claude
489	// CLI rejects the stream-json flags, retries with the legacy buffered
490	// --print/-p/--output-format=json invocation so existing non-streaming
491	// contracts remain intact.
492	func runClaudeWithFallbackFn(r *Runner, ctx context.Context, harness harnessConfig, harnessName, model string, resolvedOpts RunArgs, prompt, execDir string, timeout time.Duration) (*Result, error) {
493		result, err := runClaudeStreamingFn(r, ctx, harness, harnessName, model, resolvedOpts, prompt, execDir, timeout)
494		if err != nil {
495			return nil, err
496		}
497		if result == nil {
498			return nil, nil
499		}
500		// Streaming path succeeded (even if the bead itself failed).
501		if result.ExitCode != 2 || !claudeStreamArgsUnsupported(result.Stderr) {
502			return result, nil
503		}
504	
505		// claude CLI rejected stream-json (older build). Retry with the legacy
506		// non-streaming args so the run still completes.
507		legacyHarness := harness
508		legacyHarness.BaseArgs = []string{"--print", "-p", "--output-format", "json"}
509		args := BuildArgs(legacyHarness, buildArgsInputFromRunArgs(resolvedOpts), model)
510		stdin := ""
511		if harness.PromptMode == "stdin" {
512			stdin = prompt
513		}
514		start := time.Now()
515		execResult, execErr := r.Executor.ExecuteInDir(ctx, harness.Binary, args, stdin, execDir)
516		elapsed := time.Since(start)
517		return r.processResult(harnessName, model, harness, execResult, execErr, elapsed, ctx), nil
518	}
