520	// finalizeClaudeResult writes the session log entry and records the routing
521	// outcome, mirroring the tail end of Runner.Run for the non-streaming path.
522	func finalizeClaudeResult(r *Runner, result *Result, opts RunArgs, prompt string, elapsed time.Duration) {
523		promptSource := opts.PromptSource
