525			if opts.PromptFile != "" {
526				promptSource = opts.PromptFile
527			} else {
528				promptSource = "inline"
529			}
530		}
531		r.logSession(result, len(prompt), prompt, promptSource, opts.Correlation)
532		r.recordRoutingOutcome(result, elapsed, opts)
533	}
