// Session log JSONL schema reference.
//
// The agent harness writes one event per line to .ddx/agent-logs/agent-*.jsonl
// (or to the per-run SessionLogDir override). Every line has the envelope:
//
//	{"session_id": string, "seq": int, "type": string, "ts": RFC3339Nano, "data": {...}}
//
// Two schema modes coexist. Lean mode is always on by default and is what
// existing tooling consumes. Verbose mode is opt-in via the env var
// DDX_AGENT_LOG_VERBOSE=1; when set, the writer adds extra fields to a
// few event types so a session can be replayed and root-caused without
// loss of inputs and outputs. Lean fields are never removed in verbose
// mode — verbose is strictly additive (with the single exception that
// tool.call events are deferred until the matching tool_result arrives,
// so they can include output/duration_ms/error in one line).
//
// Per-event-type fields:
//
//	session.start (lean and verbose):
//	  data.model       string  — model id reported by the harness
//	  data.session_id  string  — session id from the harness CLI
//	  data.bead_id     string  — bead under which the session ran (may be "")
//	  data.elapsed_ms  int     — ms since session start (always 0 here)
//	  data.harness     string  — "claude" | "ddx-agent" | etc.
//
//	llm.request (lean and verbose):
//	  data.attempt_index int        — request attempt counter (0-based)
//	  data.messages      []object   — conversation messages (last user message hint used by the renderer)
//
//	llm.response (lean):
//	  data.model         string  — resolved model id
//	  data.latency_ms    int     — per-call wall time (request → response)
//	  data.tool_calls    []{name} — tool_use names emitted in this turn
//	  data.turn          int     — 1-based assistant turn count
//	  data.bead_id       string
//	  data.elapsed_ms    int     — ms since session start
//	  data.input_tokens  int     — running input tokens (latest seen)
//	  data.output_tokens int     — running output tokens (latest seen)
//	  data.attempt.cost.raw.total_tokens int — running total
//
//	llm.response (verbose adds):
//	  data.content       string  — concatenated assistant text blocks for this turn
//	  data.finish_reason string  — claude stop_reason ("end_turn", "tool_use", "max_tokens", ...)
//	  data.usage object:
//	    input_tokens                int
//	    output_tokens               int
//	    cache_creation_input_tokens int
//	    cache_read_input_tokens     int
//	    total_tokens                int
//
//	tool.call (lean):
//	  data.tool       string         — tool name
//	  data.input      object         — tool arguments as decoded JSON
//	  data.bead_id    string
//	  data.elapsed_ms int            — ms since session start
//	  data.turn       int            — assistant turn that issued the call
//
//	tool.call (verbose) — emitted when the matching tool_result arrives so output is populated:
//	  data.tool        string
//	  data.input       object
//	  data.output      string  — tool_result content (joined if structured)
//	  data.duration_ms int     — wall time from tool_use → tool_result
//	  data.error       string  — non-empty when tool_result is_error=true; empty otherwise
//	  data.bead_id     string
//	  data.elapsed_ms  int     — ms-from-session-start at the time of the originating tool_use
//	  data.turn        int     — assistant turn that issued the call
//
// Verbose mode is off by default; existing consumers of the lean schema
// (TailSessionLogs, FormatSessionLogLines, the server worker log endpoint)
// keep working unchanged because they tolerate extra fields.

// TestParseClaudeStreamVerboseMode asserts that with DDX_AGENT_LOG_VERBOSE=1
// the parser produces enriched llm.response events (content, finish_reason,
// full usage object including cache fields) and emits tool.call events
// only after the matching tool_result, with input, output, duration_ms,
// and error all populated.
func TestParseClaudeStreamVerboseMode(t *testing.T) {
	t.Setenv("DDX_AGENT_LOG_VERBOSE", "1")
	input := strings.Join([]string{
		`{"type":"system","subtype":"init","session_id":"sess-v","model":"claude-sonnet-4-6"}`,
		`{"type":"assistant","message":{"id":"m-1","model":"claude-sonnet-4-6","stop_reason":"tool_use","content":[{"type":"text","text":"running ls"},{"type":"tool_use","id":"tu-1","name":"Bash","input":{"command":"ls"}}],"usage":{"input_tokens":120,"output_tokens":42,"cache_creation_input_tokens":10,"cache_read_input_tokens":80}}}`,
		`{"type":"user","message":{"content":[{"type":"tool_result","tool_use_id":"tu-1","content":"README.md\nfoo.go","is_error":false}]}}`,
		`{"type":"assistant","message":{"id":"m-2","model":"claude-sonnet-4-6","stop_reason":"end_turn","content":[{"type":"text","text":"All done."}],"usage":{"input_tokens":260,"output_tokens":88,"cache_creation_input_tokens":0,"cache_read_input_tokens":200}}}`,
		`{"type":"result","subtype":"success","is_error":false,"duration_ms":1200,"result":"All done.","usage":{"input_tokens":260,"output_tokens":88},"total_cost_usd":0.0123,"session_id":"sess-v"}`,
	}, "\n")

	var progressBuf bytes.Buffer
	res, err := parseClaudeStream(strings.NewReader(input), &progressBuf, "sess-v", "ddx-verbose", time.Now())
	require.NoError(t, err)
	require.NotNil(t, res)

	type envelope struct {
		Type string                 `json:"type"`
		Data map[string]interface{} `json:"data"`
	}
	var llmResponses []map[string]interface{}
	var toolCalls []map[string]interface{}
	for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
		if line == "" {
			continue
		}
		var env envelope
		require.NoError(t, json.Unmarshal([]byte(line), &env))
		switch env.Type {
		case "llm.response":
			llmResponses = append(llmResponses, env.Data)
		case "tool.call":
			toolCalls = append(toolCalls, env.Data)
		}
	}
	require.Len(t, llmResponses, 2, "expected two llm.response events")
	require.Len(t, toolCalls, 1, "expected one tool.call event (deferred until tool_result)")

	// llm.response[0] — assistant turn that issued a tool_use.
	first := llmResponses[0]
	assert.Equal(t, "running ls", first["content"], "verbose llm.response must include content")
	assert.Equal(t, "tool_use", first["finish_reason"], "verbose llm.response must include finish_reason")
	usage, ok := first["usage"].(map[string]interface{})
	require.True(t, ok, "verbose llm.response must include usage object")
	assert.EqualValues(t, 120, usage["input_tokens"])
	assert.EqualValues(t, 42, usage["output_tokens"])
	assert.EqualValues(t, 10, usage["cache_creation_input_tokens"])
	assert.EqualValues(t, 80, usage["cache_read_input_tokens"])
	assert.EqualValues(t, 162, usage["total_tokens"])

	// llm.response[1] — final text turn.
	second := llmResponses[1]
	assert.Equal(t, "All done.", second["content"])
	assert.Equal(t, "end_turn", second["finish_reason"])

	// tool.call — verbose deferred event with output/duration/error populated.
	tc := toolCalls[0]
	assert.Equal(t, "Bash", tc["tool"])
	input2, ok := tc["input"].(map[string]interface{})
	require.True(t, ok, "verbose tool.call must include decoded input")
	assert.Equal(t, "ls", input2["command"])
	assert.Equal(t, "README.md\nfoo.go", tc["output"], "verbose tool.call must include tool_result output")
	_, hasDuration := tc["duration_ms"]
	assert.True(t, hasDuration, "verbose tool.call must include duration_ms")
	assert.Equal(t, "", tc["error"], "verbose tool.call must include error field (empty on success)")
	assert.Equal(t, "ddx-verbose", tc["bead_id"])
	assert.EqualValues(t, 1, tc["turn"])
}

// TestParseClaudeStreamVerboseLeanDefault asserts that the lean schema is
// the default — when DDX_AGENT_LOG_VERBOSE is unset, llm.response events
// must NOT carry the verbose-only fields and tool.call events are emitted
// immediately (without output/duration_ms/error).
func TestParseClaudeStreamVerboseLeanDefault(t *testing.T) {
	t.Setenv("DDX_AGENT_LOG_VERBOSE", "")
	input := strings.Join([]string{
		`{"type":"system","subtype":"init","session_id":"sess-l","model":"claude-sonnet-4-6"}`,
		`{"type":"assistant","message":{"id":"m-1","stop_reason":"tool_use","content":[{"type":"tool_use","id":"tu-1","name":"Bash","input":{"command":"ls"}}],"usage":{"input_tokens":1,"output_tokens":1}}}`,
		`{"type":"user","message":{"content":[{"type":"tool_result","tool_use_id":"tu-1","content":"ok"}]}}`,
		`{"type":"result","subtype":"success","result":"ok","usage":{"input_tokens":1,"output_tokens":1},"total_cost_usd":0.0001,"session_id":"sess-l"}`,
	}, "\n")

	var progressBuf bytes.Buffer
	_, err := parseClaudeStream(strings.NewReader(input), &progressBuf, "sess-l", "ddx-lean", time.Now())
	require.NoError(t, err)

	hasField := func(eventType, field string) bool {
		for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
			if line == "" {
				continue
			}
			var env struct {
				Type string                 `json:"type"`
				Data map[string]interface{} `json:"data"`
			}
			if json.Unmarshal([]byte(line), &env) != nil || env.Type != eventType {
				continue
			}
			if _, ok := env.Data[field]; ok {
				return true
			}
		}
		return false
	}
	assert.False(t, hasField("llm.response", "content"), "lean llm.response must not include content")
	assert.False(t, hasField("llm.response", "finish_reason"), "lean llm.response must not include finish_reason")
	assert.False(t, hasField("llm.response", "usage"), "lean llm.response must not include verbose usage object")
	assert.False(t, hasField("tool.call", "output"), "lean tool.call must not include output")
	assert.False(t, hasField("tool.call", "duration_ms"), "lean tool.call must not include duration_ms")
	assert.False(t, hasField("tool.call", "error"), "lean tool.call must not include error")
}

// TestParseClaudeStreamEmpty verifies the parser tolerates an empty stream
